RunSynchronousCommand.Path:
powershell.exe -ExecutionPolicy Bypass -NonInteractive -Command "
            $p = 'HKLM:\SOFTWARE\Microsoft\Windows\CurrentVersion\OOBE';
            if (-not (Test-Path $p)) { New-Item -Path $p -Force | Out-Null }
            New-ItemProperty -Path $p -Name SkipMachineOOBE -Value 1 -PropertyType DWord -Force | Out-Null;
            New-ItemProperty -Path $p -Name SkipUserOOBE   -Value 1 -PropertyType DWord -Force | Out-Null"
